mapper.select:
SELECT p.plot_code AS plotCode, r.name AS regionName, p.latitude, p.longitude, p.elevation, p.area, p.survey_year AS surveyYear, p.plot_type AS plotType, p.description, t.tree_number AS treeNumber, s.common_name AS speciesName, t.dbh, t.height, t.age, t.health_status AS healthStatus, v.measured_volume AS measuredVolume FROM plot p LEFT JOIN region r ON p.region_id = r.region_id LEFT JOIN tree t ON p.plot_id = t.plot_id LEFT JOIN species s ON t.species_id = s.species_id LEFT JOIN volume v ON t.tree_id = v.tree_id
p.region_id = #{regionId}
AND p.latitude BETWEEN #{minLat} AND #{maxLat}
AND p.longitude BETWEEN #{minLng} AND #{maxLng}
ORDER BY p.plot_code, t.tree_number
